form:Form.form:Scripts:
		function ChangeSelect()
{                          
	if (Ctrl("main").GetMode()=="LIST")
	{
		SetButtons();
		Ctrl("fecha").SetCValue(Ctrl('LIST').GetSelectAttrValue("f_fechahora"));
		ValParamList();		
	}
}

function SetCode()
{
	if(!ValParam())
		return false;
	Ctrl('c_fichadasing').SetCValue(Ctrl('f_fechahora').GetXValue() + Ctrl('e_nro_legajo_reloj').GetXValue() + "M" + Ctrl('c_tipo').GetXValue());	
	SetNow();
	return true;
}

function ChangeState()
{
	SetNow();
	if(Ctrl('LIST').GetSelectAttrValue("c_estado")=='A')
	{
		Ctrl('c_fichadasing').SetCValue(Ctrl('f_fechahora').GetXValue() + Ctrl('e_nro_legajo_reloj').GetXValue() + "M" + Ctrl('c_tipo').GetXValue());
		Ctrl('main').DoEvent('SetRestaurar');
	}
	else
	{
		Ctrl('main').DoEvent('SetAnular');
	}	
}

function ChangeType()
{
	SetNow();
	if(Ctrl('LIST').GetSelectAttrValue("c_tipo")=='E')
	{		
		Ctrl('main').DoEvent('SetSalida');
	}
	else
	{		
		Ctrl('main').DoEvent('SetEntrada');
	}
}     

function ObjtectResult()
{        
	this.processResult= function(xmlin)
		{    
		}
}

function ViewHope()
{
	openNewFlowWait('NucleusRH.Base.Tiempos_Trabajados.FichadasIng.ESPERANZAPER.guia.flow',"HELP","<DATA oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" fecha=\""+Ctrl('fecha').GetXValue()+"\" />",new ObjtectResult(),"L");
}

function SetNow()
{
	momentoActual = new Date();  
	horaImprimible = datetime2str(momentoActual).substr(0,12)+"00";    		  		  
	Ctrl('now').SetXValue(horaImprimible);		
	return true;
}

function ValParam()
{		
	if(Ctrl('PosEditFic').GetXValue() == "" && Ctrl('PreEditFic').GetXValue() && (Ctrl('EditMyFic').GetXValue() == ""  || Ctrl('EditMyFic').GetXValue() == "0"))
		return true

	momentoActual = new Date();

	if(Ctrl('PosEditFic').GetXValue() != "")
	{
		fechaComparePos = new Date(momentoActual.getFullYear(), momentoActual.getMonth(), momentoActual.getDate() + 1 +  parseInt(Ctrl('PosEditFic').GetXValue()));

		if (Ctrl('f_fechahora').TypedValue() > fechaComparePos) 
		{
			alert('La fecha de la fichada supera la cantidad de días posteriores a la fecha actual permitidos ('+Ctrl('PosEditFic').GetXValue()+').');
			return false;
		}
	}

	if(Ctrl('PreEditFic').GetXValue() != "")
	{
		fechaComparePre = new Date(momentoActual.getFullYear(), momentoActual.getMonth(), momentoActual.getDate() - 1 - parseInt(Ctrl('PreEditFic').GetXValue()));

		if (Ctrl('f_fechahora').TypedValue() < fechaComparePre) 
		{
			alert('La fecha de la fichada supera la cantidad de días previos a la fecha actual permitidos ('+Ctrl('PreEditFic').GetXValue()+').');
			return false;
		}
	}

	if(Ctrl('EditMyFic').GetXValue() == "1")
	{
		var user;				
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();	
		user = nSQL.GetOBJ(Ctrl("main").getResource("QRY_USER"), "<PARAM oi_personal_emp=\""+Ctrl("oi_personal_emp").GetXValue()+"\" />"); 			

		if(Ctrl("etty").GetXValue() == user.oi_usuario_sistema)
		{			
			alert('No se permite agregar fichadas para el propio usuario.');
			return false;
		}
	}

	return true;	
}

function ValParamList()
{
	if(Ctrl('PosEditFic').GetXValue() == "" && Ctrl('PreEditFic').GetXValue() && (Ctrl('EditMyFic').GetXValue() == ""  || Ctrl('EditMyFic').GetXValue() == "0"))
	{		
		SetButtons();		
		return true;
	}

	momentoActual = new Date();

	if(Ctrl('PosEditFic').GetXValue() != "")
	{
		fechaComparePos = new Date(momentoActual.getFullYear(), momentoActual.getMonth(), momentoActual.getDate() + 1 +  parseInt(Ctrl('PosEditFic').GetXValue()));

		if (str2datetime(Ctrl("fecha").GetXValue()) > fechaComparePos) 
		{			
			DisableButtons();
			return true;
		}
		else
			SetButtons();		
	}

	if(Ctrl('PreEditFic').GetXValue() != "")
	{		
		fechaComparePre = new Date(momentoActual.getFullYear(), momentoActual.getMonth(), momentoActual.getDate() - 1 - parseInt(Ctrl('PreEditFic').GetXValue()));

		if (str2datetime(Ctrl('fecha').GetXValue()) < fechaComparePre) 
		{						
			DisableButtons();
			return true;
		}
		else
			SetButtons();
	}	

	if(Ctrl('EditMyFic').GetXValue() == "1")
	{
		var user;				
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();	
		user = nSQL.GetOBJ(Ctrl("main").getResource("QRY_USER"), "<PARAM oi_personal_emp=\""+Ctrl("oi_personal_emp").GetXValue()+"\" />"); 			

		if(Ctrl("etty").GetXValue() == user.oi_usuario_sistema)
		{			
			DisableButtons();
			return true;
		}
		else
			SetButtons();
	}
	return true;
}

function SetButtons()
{
	CtrlEnabled("DELETE", (Ctrl('LIST').GetSelectAttrValue("img")?false:true));
	CtrlEnabled("EDIT", (Ctrl('LIST').GetSelectAttrValue("img")?false:true));
	CtrlEnabled("ESTADO", (Ctrl('LIST').GetSelectAttrValue("img")?false:true));
	CtrlEnabled("TIPO", (Ctrl('LIST').GetSelectAttrValue("img")?false:true));
	CtrlEnabled("DELETE", (Ctrl('LIST').GetSelectAttrValue("c_origen")!="T"));
}

function DisableButtons()
{
	CtrlEnabled("DELETE", false);
	CtrlEnabled("EDIT", false);
	CtrlEnabled("ESTADO", false);
	CtrlEnabled("TIPO", false);
}

function GotoHorario()
{
	openNewFlowWait("NucleusRH.Base.Tiempos_Trabajados.Personal.Horarios.flow","initializerep",'<ID oi_personal_emp="'+Ctrl('oi_personal_emp').GetXValue()+ '" periodo="'+Ctrl('fecha').GetXValue().substring(0,6)+'" />',new ObjtectResult(),"L");
}

function GotoLicencia()
{
	openNewFlowWait("NucleusRH.Base.Tiempos_Trabajados.Personal.Licencias.flow","initializerep",'<ID oi_personal_emp="'+Ctrl('oi_personal_emp').GetXValue()+ '" periodo="'+Ctrl('fecha').GetXValue().substring(0,6)+'" />',new ObjtectResult(),"L");
}

function GotoNovedad()
{
	openNewFlowWait("NucleusRH.Base.Tiempos_Trabajados.Personal.Novedades.flow","initializerep",'<ID oi_personal_emp="'+Ctrl('oi_personal_emp').GetXValue()+ '" fecha="'+Ctrl('fecha').GetXValue().substring(0,8)+'" />',new ObjtectResult(),"L");
}
